INSERT INTO public.legal_references (permit_type, description, frequency_basis, estimated_cost, disclaimer)
VALUES ('uso_suelo', 'El Informe de Compatibilidad de Uso de Suelo (ICUS) verifica que la actividad económica que se desea realizar es compatible con la zonificación del predio. Es prerequisito para obtener la patente municipal y la LUAE.', 'Trámite por evento: se obtiene al abrir un nuevo establecimiento o al cambiar de actividad económica. No tiene vencimiento fijo, pero puede requerirse nuevamente si cambia la normativa de zonificación o el uso del suelo del sector. En algunos cantones se solicita renovación periódica.', 'Variable por municipio. En Quito: ~$5–$30 USD por trámite.', 'La zonificación varía drásticamente entre barrios y cantones. Un uso compatible en La Mariscal puede no serlo en La Floresta. Siempre consultar el PUOS vigente del municipio.');

