INSERT INTO public.legal_references (permit_type, description, frequency_basis, estimated_cost, disclaimer)
VALUES ('rotulacion', 'El permiso de publicidad exterior o rotulación autoriza la instalación de rótulos, letreros, toldos y cualquier elemento de publicidad visible desde el espacio público. En Quito se gestiona como componente de la LUAE.', 'Trámite por evento: se solicita al instalar o modificar rotulación. No tiene vencimiento anual fijo, aunque en Quito se renueva como componente de la LUAE. Modificaciones de diseño, tamaño o ubicación requieren nueva autorización.', 'En Quito: variable según metros cuadrados de publicidad. Rango típico para restaurantes: $20–$150 USD.', 'Las normas de publicidad exterior varían significativamente entre municipios. En zonas patrimoniales (Centro Histórico de Quito, por ejemplo) aplican restricciones adicionales.');

